function PhoneMockup(){const[li,setLi]=useState(0);const[vi,setVi]=useState(0);const[typing,setTyping]=useState(false);const cv=convos[li];useEffect(()=>{if(vi>=cv.msgs.length){const t=setTimeout(()=>{setLi(p=>(p+1)%convos.length);setVi(0);},2400);return()=>clearTimeout(t);}const msg=cv.msgs[vi];if(msg.f==="u"){setVi(p=>p+1);}else{setTyping(true);const t=setTimeout(()=>{setTyping(false);setVi(p=>p+1);},400+Math.random()*400);return()=>clearTimeout(t);}},[vi,li,cv.msgs]);return(<div className="phW"><motion.div className="phGlow" animate={{opacity:[0.12,0.3,0.12]}} transition={{duration:5,repeat:Infinity}}/><motion.div className="phF" initial={{opacity:0,y:16}} whileInView={{opacity:1,y:0}} viewport={{once:true}}><div className="phB"><div className="phDI"/><div className="phS"><div className="phH"><div className="phAv"><Image src="/laura-avatar.png" alt="Laura" fill sizes="22px" style={{objectFit:"cover"}}/></div><div><div className="phN">Laura <svg width="10" height="10" viewBox="0 0 24 24" fill="none"><path d="M12 1L14.9 3.6L18.6 3.2L19.4 6.8L22.5 8.7L21.2 12.2L22.5 15.7L19.4 17.6L18.6 21.2L14.9 20.8L12 23.4L9.1 20.8L5.4 21.2L4.6 17.6L1.5 15.7L2.8 12.2L1.5 8.7L4.6 6.8L5.4 3.2L9.1 3.6L12 1Z" fill="#22C55E"/><path d="M8.5 12.5L10.5 14.5L15.5 9.5" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg></div><div className="phOn"><span className="phOnD"/>online</div></div></div><AnimatePresence mode="wait"><motion.div key={li} initial={{opacity:0}} animate={{opacity:1}} exit={{opacity:0}} className="phLang">{cv.flag} {cv.lang}</motion.div></AnimatePresence><div className="phBdy">{cv.msgs.slice(0,vi).map((msg,i)=>(<motion.div key={`${li}-${i}`} initial={{opacity:0,y:3}} animate={{opacity:1,y:0}} className={`phR ${msg.f==="u"?"phRR":"phRL"}`}>{msg.f==="a"?<div className="phAct">{msg.t}</div>:<div className={`phBb ${msg.f==="u"?"phBbU":"phBbL"}`}>{msg.t}{msg.f==="u"&&<span className="phMt"><svg width="10" height="7" viewBox="0 0 20 14" fill="none"><path d="M1.5 7.6L4.7 10.8L10.2 5.2" stroke="#53BDEB" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round"/><path d="M7.3 7.6L10.5 10.8L18.2 3.2" stroke="#53BDEB" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round"/></svg></span>}</div>}</motion.div>))}{typing&&<div className="phR phRL"><div className="phBb phBbL phTy"><span/><span/><span/></div></div>}</div><div className="phCo"><div className="phCoF"><span className="phCoT">Message</span></div><div className="phCoM"><Mic size={10} color="#fff"/></div></div></div></div></motion.div></div>);}

/* ─── Canvas Globe ─── */
const gs=[{country:"United Kingdom",flag:"\u{1F1EC}\u{1F1E7}",name:"Sarah, 34, Leeds",quote:"I called at 8:01am. Busy. By 8:15 all slots were gone. Three weeks of this.",laura:"Laura prepares a structured callback request so the practice can respond more efficiently.",lat:54,lng:-1.5},{country:"United States",flag:"\u{1F1FA}\u{1F1F8}",name:"Marcus, 28, Chicago",quote:"I delayed seeing a doctor for six months because I was terrified of the cost.",laura:"Laura surfaces lower-cost options and community clinics near you automatically.",lat:41.8,lng:-87.6},{country:"Nigeria",flag:"\u{1F1F3}\u{1F1EC}",name:"Amina, 41, Lagos",quote:"Four doctors for ten thousand people. I spent two days trying to find someone.",laura:"Laura searches provider availability in real time and helps route you to whoever can see you soonest.",lat:6.5,lng:3.4},{country:"India",flag:"\u{1F1EE}\u{1F1F3}",name:"Priya, 55, Jaipur",quote:"My mother lives two hours from the nearest clinic. She never knows when to worry.",laura:"Laura helps assess urgency remotely and tells you whether to travel now or monitor at home.",lat:26.9,lng:75.8},{country:"Brazil",flag:"\u{1F1E7}\u{1F1F7}",name:"Lucas, 23, London",quote:"I moved to London and could not explain my symptoms in English.",laura:"Laura captures symptoms in your language, generates a structured bilingual note, and helps you share it before you arrive.",lat:51.5,lng:-0.1}];
function latLngToXYZ(lat:number,lng:number){const phi=(90-lat)*(Math.PI/180);const theta=(lng+180)*(Math.PI/180);return{x:-Math.sin(phi)*Math.cos(theta),y:Math.cos(phi),z:Math.sin(phi)*Math.sin(theta)};}
function CanvasGlobe({active}:{active:number}){const canvasRef=useRef<HTMLCanvasElement>(null);const rotRef=useRef(0.4);const frameRef=useRef(0);useEffect(()=>{const canvas=canvasRef.current;if(!canvas)return;const ctx=canvas.getContext("2d");if(!ctx)return;const dpr=window.devicePixelRatio||1;function resize(){if(!canvas)return;const rect=canvas.getBoundingClientRect();canvas.width=rect.width*dpr;canvas.height=rect.height*dpr;}resize();const N=300;const golden=Math.PI*(3-Math.sqrt(5));const dots:{x:number;y:number;z:number}[]=[];for(let i=0;i<N;i++){const theta=golden*i;const phi=Math.acos(1-2*(i+0.5)/N);dots.push({x:Math.cos(theta)*Math.sin(phi),y:Math.cos(phi),z:Math.sin(theta)*Math.sin(phi)});}const cityXYZ=gs.map(g=>latLngToXYZ(g.lat,g.lng));function draw(){if(!canvas||!ctx)return;const w=canvas.width/dpr;const h=canvas.height/dpr;const R=Math.min(w,h)*0.42;const cx=w/2;const cy=h/2;const rot=rotRef.current;const cosR=Math.cos(rot);const sinR=Math.sin(rot);ctx.setTransform(dpr,0,0,dpr,0,0);ctx.clearRect(0,0,w,h);const glow=ctx.createRadialGradient(cx-R*0.2,cy-R*0.2,0,cx,cy,R*1.3);glow.addColorStop(0,"rgba(201,149,107,0.07)");glow.addColorStop(0.6,"rgba(201,149,107,0.02)");glow.addColorStop(1,"transparent");ctx.fillStyle=glow;ctx.fillRect(0,0,w,h);ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.strokeStyle="rgba(192,184,164,0.25)";ctx.lineWidth=0.8;ctx.stroke();const sg=ctx.createRadialGradient(cx-R*0.25,cy-R*0.25,R*0.1,cx,cy,R);sg.addColorStop(0,"rgba(248,246,241,0.06)");sg.addColorStop(1,"rgba(224,218,200,0.03)");ctx.fillStyle=sg;ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.fill();ctx.strokeStyle="rgba(200,192,172,0.07)";ctx.lineWidth=0.5;for(let lat=-60;lat<=60;lat+=30){const p=(90-lat)*Math.PI/180;const rr=Math.sin(p)*R;const ry=cy-Math.cos(p)*R;ctx.beginPath();ctx.ellipse(cx,ry,rr,rr*0.12,0,0,Math.PI*2);ctx.stroke();}for(const p of dots){const x=p.x*cosR+p.z*sinR;const z=-p.x*sinR+p.z*cosR;if(z<-0.05)continue;const sx=cx+x*R;const sy=cy-p.y*R;const alpha=Math.max(0,Math.min(1,(z+0.3)*0.6));ctx.beginPath();ctx.arc(sx,sy,1+z*0.8,0,Math.PI*2);ctx.fillStyle=`rgba(180,168,148,${alpha*0.55})`;ctx.fill();}const projected:{sx:number;sy:number;z:number}[]=[];for(let i=0;i<cityXYZ.length;i++){const p=cityXYZ[i];const x=p.x*cosR+p.z*sinR;const z=-p.x*sinR+p.z*cosR;const sx=cx+x*R;const sy=cy-p.y*R;projected.push({sx,sy,z});if(z<0)continue;if(i===active){ctx.beginPath();ctx.arc(sx,sy,8,0,Math.PI*2);ctx.fillStyle="rgba(201,149,107,0.15)";ctx.fill();ctx.beginPath();ctx.arc(sx,sy,14,0,Math.PI*2);ctx.fillStyle="rgba(201,149,107,0.06)";ctx.fill();}ctx.beginPath();ctx.arc(sx,sy,i===active?4:2.5,0,Math.PI*2);ctx.fillStyle=i===active?c.warm:"rgba(176,168,148,0.7)";ctx.fill();}for(let i=0;i<cityXYZ.length;i++){const next=(i+1)%cityXYZ.length;const a=projected[i];const b=projected[next];if(a.z<-0.2||b.z<-0.2)continue;ctx.beginPath();ctx.moveTo(a.sx,a.sy);ctx.quadraticCurveTo((a.sx+b.sx)/2,(a.sy+b.sy)/2-Math.abs(a.sx-b.sx)*0.2,b.sx,b.sy);ctx.strokeStyle=i===active?"rgba(201,149,107,0.35)":"rgba(201,149,107,0.06)";ctx.lineWidth=i===active?1.2:0.5;ctx.setLineDash(i===active?[4,3]:[]);ctx.stroke();ctx.setLineDash([]);}rotRef.current+=0.002;frameRef.current=requestAnimationFrame(draw);}frameRef.current=requestAnimationFrame(draw);const ro=new ResizeObserver(()=>{resize();});ro.observe(canvas);return()=>{cancelAnimationFrame(frameRef.current);ro.disconnect();};},[active]);return<canvas ref={canvasRef} className="globeCanvas"/>;}

function GlobeSection(){const[a,setA]=useState(0);const tr=useRef<ReturnType<typeof setTimeout>|null>(null);const reset=useCallback(()=>{if(tr.current)clearTimeout(tr.current);tr.current=setTimeout(()=>setA(p=>(p+1)%gs.length),6000);},[]);useEffect(()=>{reset();return()=>{if(tr.current)clearTimeout(tr.current);};},[a,reset]);const s=gs[a];return(<section className="globeSec"><div className="container"><FI><div className="shW"><h2 className="serif shT">The problem is global. The relief is human.</h2><p className="shB">Laura becomes more believable once people see the problem is global, human, and painfully administrative.</p></div></FI><div className="globeW"><div className="globeV"><CanvasGlobe active={a}/></div><div className="globeC"><AnimatePresence mode="wait"><motion.div key={a} initial={{opacity:0,y:10}} animate={{opacity:1,y:0}} exit={{opacity:0,y:-6}} transition={{duration:0.3}} className="globeStory"><div className="globeCtry"><span style={{fontSize:"18px"}}>{s.flag}</span><span className="globeCtryN">{s.country}</span></div><p className="serif globeQ">&ldquo;{s.quote}&rdquo;</p><p className="globeNm">{s.name}</p><div className="globeL"><div className="globeLA"><Image src="/laura-avatar.png" alt="Laura" fill sizes="22px" style={{objectFit:"cover"}}/></div><p className="globeLT">{s.laura}</p></div></motion.div></AnimatePresence><div className="globeNav"><div className="globeDs">{gs.map((_,i)=><button key={i} className={`globeD${i===a?" globeDA":""}`} onClick={()=>setA(i)}/>)}</div><div className="globeAs"><button className="globeA" onClick={()=>setA(p=>(p-1+5)%5)}><ChevronLeft size={15}/></button><button className="globeA" onClick={()=>setA(p=>(p+1)%5)}><ChevronRight size={15}/></button></div></div></div></div></div></section>);}

/* ─── Terminal (fixed) ─── */
function SDKTerminal(){const lines=useMemo(()=>['$ npm install @omela/laura-sdk','','  import { Laura } from "@omela/laura-sdk";','','  const laura = new Laura({','    apiKey: process.env.OMELA_KEY,','    region: "eu-west-2"','  });','','  const session = await laura.navigate({','    userId: "patient_4102",','    lang: "fr",','    concern: "prescription renewal"','  });','','  // Laura found 2 practices, drafted request','  Done in 1.1s'],[]);const[vl,setVl]=useState(0);const[ci,setCi]=useState(0);useEffect(()=>{if(vl>=lines.length){const t=setTimeout(()=>{setVl(0);setCi(0);},3000);return()=>clearTimeout(t);}const line=lines[vl];if(ci<line.length){const t=setTimeout(()=>setCi(p=>p+1),line.startsWith("  //")?36:18);return()=>clearTimeout(t);}else{const t=setTimeout(()=>{setVl(p=>p+1);setCi(0);},line===""?50:140);return()=>clearTimeout(t);}},[vl,ci,lines]);return<div className="trm"><div className="trmT"><div className="trmD"><span/><span/><span/></div><span className="trmTi">Laura SDK</span><Soon/></div><div className="trmB">{lines.slice(0,vl+1).map((line,i)=>{const a2=i===vl;return<div key={i} className="trmL" style={{color:line.startsWith("  Done")||line.startsWith("  //")?"#4ADE80":line.startsWith("$")?"#E2E8F0":"#94A3B8"}}>{a2?line.slice(0,ci):line}{a2&&<span className="trmC">|</span>}</div>;})}</div></div>;}

/* ─── Roadmap (glass, swipeable, dots) ─── */
const roadmapItems=[{title:"GP request routing",desc:"Laura will help submit callback and prescription requests directly through supported practice channels.",stage:"Stage 2",emoji:"\u{1F4E8}"},{title:"Practice portal",desc:"A dashboard for care teams to manage structured intake, urgency triage, and patient routing.",stage:"Stage 2",emoji:"\u{1F3E5}"},{title:"WhatsApp access",desc:"Reach Laura through WhatsApp for an even simpler, mobile-first care navigation experience.",stage:"Stage 2",emoji:"\u{1F4F1}"},{title:"Multilingual notes",desc:"Full 40+ language support with bilingual structured notes for the practice.",stage:"Stage 2",emoji:"\u{1F30D}"},{title:"Telehealth pathways",desc:"Laura connects you to telehealth consultations where in-person visits are not practical.",stage:"Stage 3",emoji:"\u{1FA7A}"}];

function RoadmapCards(){const scrollRef=useRef<HTMLDivElement>(null);const[active,setActive]=useState(0);function onScroll(){const el=scrollRef.current;if(!el)return;const children=Array.from(el.children) as HTMLElement[];const mid=el.scrollLeft+el.clientWidth/2;let nearest=0;let smallest=Infinity;children.forEach((child,i)=>{const center=child.offsetLeft+child.clientWidth/2;const dist=Math.abs(center-mid);if(dist<smallest){smallest=dist;nearest=i;}});setActive(nearest);}function scrollTo(i:number){const el=scrollRef.current;if(!el)return;const child=el.children[i] as HTMLElement;if(child)el.scrollTo({left:child.offsetLeft-12,behavior:"smooth"});setActive(i);}return(<section className="sec"><div className="container"><FI><div className="shW"><h2 className="serif shT">Where Laura is going.</h2><p className="shB">We are starting with care navigation first. Here is what comes next.</p></div></FI><p className="roadHint">Swipe to explore</p><div className="roadScroll" ref={scrollRef} onScroll={onScroll}>{roadmapItems.map((item,i)=>(<motion.div key={item.title} className="roadCard" initial={{opacity:0,y:14}} whileInView={{opacity:1,y:0}} viewport={{once:true}} transition={{delay:i*0.08}}><div className="roadTop"><motion.span className="roadEmoji" animate={{y:[0,-4,0],rotate:[0,5,-5,0]}} transition={{duration:3+i*0.3,repeat:Infinity,ease:"easeInOut"}}>{item.emoji}</motion.span><motion.span className="roadSt" animate={{scale:[1,1.05,1]}} transition={{duration:2,repeat:Infinity,delay:i*0.4}}>{item.stage}</motion.span></div><h4 className="roadTi">{item.title}</h4><p className="roadDs">{item.desc}</p></motion.div>))}</div><div className="roadDots">{roadmapItems.map((_,i)=><button key={i} className={`roadDot${i===active?" roadDotA":""}`} onClick={()=>scrollTo(i)}/>)}</div></div></section>);}

